3543 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
3544                                                FPClassTest DemandedMask,
3545                                                KnownFPClass &Known,
3546                                                unsigned Depth) {
3547   Use &U = I->getOperandUse(OpNo);
3548   Value *V = U.get();
3549   Type *VTy = V->getType();
3550 
3551   if (DemandedMask == fcNone) {
3552     if (isa<PoisonValue>(V))
3553       return false;
3554     replaceUse(U, PoisonValue::get(VTy));
3555     return true;
3556   }
3557 
3558   // Handle constant
3559   Instruction *VInst = dyn_cast<Instruction>(V);
3560   if (!VInst) {
3561     // Handle constants and arguments
3562     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3563     Known.knownNot(~DemandedMask);
3564 
3565     if (Known.KnownFPClasses == fcNone) {
3566       if (isa<PoisonValue>(V))
3567         return false;
3568       replaceUse(U, PoisonValue::get(VTy));
3569       return true;
3570     }
3571 
3572     // Do not try to replace values which are already constants (unless we are
3573     // folding to poison). Doing so could promote poison elements to non-poison
3574     // constants.
3575     if (isa<Constant>(V))
3576       return false;
3577 
3578     Value *FoldedToConst = getFPClassConstant(VTy, Known.KnownFPClasses);
3579     if (!FoldedToConst || FoldedToConst == V)
3580       return false;
3581 
3582     replaceUse(U, FoldedToConst);
3583     return true;
3584   }
3585 
3586   if (const CallBase *CB = dyn_cast<CallBase>(VInst)) {
3587     FPClassTest NoFPClass = CB->getParamNoFPClass(U.getOperandNo());
3588     DemandedMask &= ~NoFPClass;
3589   }
3590 
3591   if (Depth == MaxAnalysisRecursionDepth) {
3592     Known.knownNot(~DemandedMask);
3593     return false;
3594   }
3595 
3596   Value *NewVal;
3597 
3598   if (VInst->hasOneUse()) {
3599     // If the instruction has one use, we can directly simplify it.
3600     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3601   } else {
3602     // If there are multiple uses of this instruction, then we can simplify
3603     // VInst to some other value, but not modify the instruction.
3604     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3605                                                 Depth);
3606   }
3607 
3608   if (!NewVal)
3609     return false;
3610   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3611     salvageDebugInfo(*OpInst);
3612 
3613   replaceUse(U, NewVal);
3614   return true;
3615 }
